input.command:
kubectl -n ingress-nginx patch configmap ingress-nginx-controller --type merge -p '{
  "data": {
    "http-snippet": "limit_req_zone $binary_remote_addr zone=api_ratelimit:10m rate=20r/m;"
  }
}' 2>&1

kubectl -n ingress-nginx patch configmap ingress-nginx-controller --type merge -p '{
  "data": {
    "allow-snippet-annotations": "true",
    "http-snippet": "limit_req_zone $binary_remote_addr zone=api_ratelimit:10m rate=20r/m;"
  }
}' 2>&1

kubectl -n ingress-nginx patch configmap ingress-nginx-controller --type merge -p '{
  "data": {
    "allow-snippet-annotations": "true",
    "http-snippet": null
  }
}' 2>&1
